// ── Helper functions ────────────────────────────────────────────

func stateLabel(state string) string {
	switch state {
	case StateOpen:
		return "Open"
	case StateActive:
		return "Active"
	case StateReview:
		return "Review"
	case StateDone:
		return "Done"
	case StateClosed:
		return "Closed"
	default:
		return state
	}
}

func stateBgClass(state string) string {
	switch state {
	case StateOpen:
		return "bg-gray-100 text-gray-600"
	case StateActive:
		return "bg-indigo-100 text-indigo-700"
	case StateReview:
		return "bg-amber-100 text-amber-700"
	case StateDone:
		return "bg-emerald-100 text-emerald-700"
	case StateClosed:
		return "bg-slate-100 text-slate-600"
	default:
		return "bg-gray-100 text-gray-600"
	}
}

func stateColorHex(state string) string {
	switch state {
	case StateOpen:
		return "#6B7280"
	case StateActive:
		return "#6366F1"
	case StateReview:
		return "#F59E0B"
	case StateDone:
		return "#10B981"
	case StateClosed:
		return "#94A3B8"
	default:
		return "#6B7280"
	}
}

func priorityDotHex(priority string) string {
	switch priority {
	case PriorityUrgent:
		return "#EF4444"
	case PriorityHigh:
		return "#F59E0B"
	case PriorityMedium:
		return "#6366F1"
	case PriorityLow:
		return "#9CA3AF"
	default:
		return "#9CA3AF"
	}
}

func kindBadgeClass(kind string) string {
	switch kind {
	case KindTask, SpaceProject:
		return "bg-indigo-100 text-indigo-700"
	case KindPost, SpaceCommunity:
		return "bg-emerald-100 text-emerald-700"
	case KindThread, SpaceTeam:
		return "bg-amber-100 text-amber-700"
	case KindComment:
		return "bg-gray-100 text-gray-600"
	default:
		return "bg-gray-100 text-gray-600"
	}
}

func opBadgeClass(op string) string {
	switch op {
	case "intend", "decompose":
		return "bg-indigo-100 text-indigo-700"
	case "express", "discuss":
		return "bg-emerald-100 text-emerald-700"
	case "respond":
		return "bg-gray-100 text-gray-600"
	case "complete":
		return "bg-emerald-100 text-emerald-700"
	case "claim", "assign":
		return "bg-amber-100 text-amber-700"
	case "prioritize":
		return "bg-purple-100 text-purple-700"
	case "review":
		return "bg-amber-100 text-amber-700"
	case "progress":
		return "bg-blue-100 text-blue-700"
	default:
		return "bg-gray-100 text-gray-600"
	}
}

func initial(name string) string {
	if name == "" {
		return ""
	}
	runes := []rune(name)
	if len(runes) == 0 {
		return ""
	}
	return string(runes[0:1])
}

func childProgress(node Node) string {
	if node.ChildCount == 0 {
		return "width: 0%"
	}
	pct := (node.ChildDone * 100) / node.ChildCount
	return fmt.Sprintf("width: %d%%", pct)
}

func childProgressSlice(nodes []Node) string {
	if len(nodes) == 0 {
		return "width: 0%"
	}
	done := countDone(nodes)
	pct := (done * 100) / len(nodes)
	return fmt.Sprintf("width: %d%%", pct)
}

func countDone(nodes []Node) int {
	n := 0
	for _, nd := range nodes {
		if nd.State == StateDone {
			n++
		}
	}
	return n
}

